import{_ as i}from"./chunks/ArticleMetadata.Sb1DYAHo.js";import{_ as p,D as l,o as s,c,I as v,w as J,k as r,a as d,R as g,b as m,e as h}from"./chunks/framework.FVQzxbLi.js";import"./chunks/md5.RtphNWHi.js";const u="/assets/202010011205888.R6C4Vvg9.jpg",_="/assets/202010011205999.0Ju53Vlf.jpg",b="/assets/202010011206888.mZ3Rxz0R.png",E="/assets/202010011206999.qr5ulv-f.png",f="/assets/202010011209888.5PVA18TA.png",k="/assets/202010011209999.cecaEv99.png",P="/assets/202010011210888.i4d1vWr1.png",S="/assets/202010011210999.lKU9a9vw.png",q="/assets/202010011211888.rcL3gkzw.jpg",D="/assets/202010011212999.ZFPQrz3f.png",x="/assets/202010011215888.zUYP9cA-.png",A="/assets/202010011216999.h7LzfNeO.png",y=JSON.parse('{"title":"Java基础快速入门","description":"","frontmatter":{"title":"Java基础快速入门","author":"ting","date":"2020/10/01 10:24","categories":["Java基础快速入门"],"tags":["Java","Java基础"]},"headers":[],"relativePath":"courses/java/index.md","filePath":"courses/java/index.md","lastUpdated":1742606992000}'),K={name:"courses/java/index.md"},T=r("h1",{id:"java-基础快速入门",tabindex:"-1"},[d("Java 基础快速入门 "),r("a",{class:"header-anchor",href:"#java-基础快速入门","aria-label":'Permalink to "Java 基础快速入门"'},"​")],-1),w=g('<p><strong>C：</strong> Hi，大家好！从本篇起，笔者将开辟一个新的专栏《Java 基础快速入门》，这个专栏初期将涵盖 Java 语法、Java OOP、Java 高级特性三大部分。</p><p>当然了，此类教程在网络上不胜枚举，笔者在以前也是比较推荐大家去看谁谁谁的什么什么文章，但后来发现，这些知识是散布在网络间的，所以分散是第一个大问题；而且由于时间和作者等因素，有些内容至今还没有得到更新，这就导致一个知识的滞后性。</p><p>所以，笔者再开辟此专栏的目的，就是为了继续做好知识更新延续和传播，未来对这些内容还会继续编辑更新，仅仅希望能让后辈在学习 Java 语言的路上可以走的顺畅一些，也可以在前期少走一些弯路。</p><p><img src="'+u+'" alt="202010011205888"></p><h2 id="程序概述" tabindex="-1">程序概述 <a class="header-anchor" href="#程序概述" aria-label="Permalink to &quot;程序概述&quot;">​</a></h2><p>好了，言归正传。从看到本篇的那一刻起，你就已经推开了 IT 编程的大门。自此，程序一词或将改变你未来的人生轨迹。未来的你，按键行云流水，脑内 CPU 高速运转，屏幕切换间，高可用、高扩展、高安全性的” 完美”程序，将由你所著。[<a href="http://www.acfun.cn/v/ac4552801" target="_blank" rel="noreferrer">未来的你</a>]</p><p><img src="'+_+'" alt="202010011205999"></p><p>首先我们来看看程序的概念，程序在现世纪存在两种含义，即生活中的程序和计算机中的程序。</p><p><img src="'+b+'" alt="202010011206888"></p><h3 id="生活中程序" tabindex="-1">生活中程序 <a class="header-anchor" href="#生活中程序" aria-label="Permalink to &quot;生活中程序&quot;">​</a></h3><p><strong>生活中的程序：</strong> 我们去银行办理业务或者在学校时因事请假再或者在工作中去办理报销，这些场景我们都不陌生。我们一遍一遍，一步一步的执行着所谓的流程和手续（套路），这就是生活中的程序。</p><h3 id="计算机中的程序" tabindex="-1">计算机中的程序 <a class="header-anchor" href="#计算机中的程序" aria-label="Permalink to &quot;计算机中的程序&quot;">​</a></h3><p>在本世纪的今天，现实生活中的程序你可能已经把它换了个称呼，比如：流程或者手续。而程序这个概念，更多的时候已经被你安放到了手机上的 APP，或者计算机上的 QQ 等方面。它们的确是程序，是由我们未来的同行，前辈所创造编写，<strong>编写这些程序的过程，就是所谓的编程</strong> 。</p><div class="tip custom-block"><p class="custom-block-title">笔者说</p><p>软件不是程序，软件是比应用程序更大的概念，<strong>软件是程序、数据及相关文档的完整集合</strong> 。可延伸阅读张海藩和吕云翔所著的《软件工程 第 4 版》</p></div><p>但是如果单单这么理解程序，可就有点小儿科了。下面的[ 百度百科 ]，解释的还挺不错！程序其实是一个<strong>指令</strong> 的集合。</p><p><img src="'+E+'" alt="202010011206999"></p><p><strong>何为指令呢？</strong> 比方说：我是一位老板（目前不是），我有个女秘书（目前没有），每天我的行程安排或者一些繁琐的事项都交给了我秘书去做，我告诉秘书去帮我邀约一位客人，她就如是去做了。我告诉秘书去帮我通知一下部门要开会了，她也会如是去通知。<strong>这个比方里老板所告诉秘书的一件件事就是一个个指令</strong> ，而秘书就是接收指令然后去执行的人。</p><p><img src="'+f+'" alt="202010011209888"></p><p>换到计算机世界的概念，我们被称为<strong>程序员/码农</strong> ，如果想让计算机这些秘书去执行一些操作，例如在屏幕上输出一些内容或者自动绘制一个小猪佩奇图像等，就需要去给计算机下达指令。<strong>学习编程就是在学习给计算机秘书下达指令的过程而已。</strong></p><p><img src="'+k+'" alt="202010011209999"></p><h3 id="程序和程序的关系" tabindex="-1">程序和程序的关系 <a class="header-anchor" href="#程序和程序的关系" aria-label="Permalink to &quot;程序和程序的关系&quot;">​</a></h3><p>从上面我们理解了程序的两种含义，它们之间是否存在什么关系呢？其实计算机中的程序绝大多数都是因为现实中的某些流程/程序，很是麻烦，耗时或者产生一些资源的浪费（纸张），所以在有了计算机帮助之后，我们人类就将现实生活中的这些程序，以计算机中的程序表现出来了。<strong>例如：</strong> 在线挂号，在线购物，在线选课、OA 系统等。</p><p><strong>一句话可以阐述这个关系：</strong> 我们编程就是将现实生活中的业务程序移植到计算机中，以计算机指令的形式表现出来。</p><h2 id="编程语言概述" tabindex="-1">编程语言概述 <a class="header-anchor" href="#编程语言概述" aria-label="Permalink to &quot;编程语言概述&quot;">​</a></h2><p>了解完程序的概念，那这些程序指令我们是怎么告诉计算机的？口头告诉？脑电波交流？显然不是，那我们写自然语言来告诉计算机要做什么？不好意思的是，计算机并不能看懂，它只能看懂二进制（0 1 这种数制）。<strong>早期的计算机从业者就是在敲打 0 1 来告诉计算机需要做什么，但是对于我们人类来讲，这一堆 0110 阅读起来太难了，所以后期的发展中，我们用自然语言定义了一些特殊的语法，再通过一个”翻译官”(编译器)帮我们翻译给计算机看，这样就能实现计算机来执行我们的指令，而且我们自己也能看懂自己写的是什么。</strong> 上述提到的特殊语法就是编程语言，也被称为计算机语言。</p><p><img src="'+P+'" alt="202010011210888"></p><h3 id="主流的编程语言" tabindex="-1">主流的编程语言 <a class="header-anchor" href="#主流的编程语言" aria-label="Permalink to &quot;主流的编程语言&quot;">​</a></h3><p>编程语言太多了，怎么定义语法的都有。这也很正常，就好像当今世界，自然语言都千奇百怪呢。所以我们不需要去过多的关注偏门的”小语种”，只需要去关注一下当今 IT 编程领域的主角们即可。[ 参见<a href="https://www.tiobe.com/tiobe-index/" target="_blank" rel="noreferrer">TIOBE </a>]</p><p>下图是知名排行榜的统计数据，类似的网站有 PYPL 等。TIOBE 排行榜是根据互联网上有经验的程序员、课程和第三方厂商的数量，并使用搜索引擎（如 Google、Bing、Yahoo!）以及 Wikipedia、Amazon、YouTube 统计出排名数据，只是反映某个编程语言的热门程度，并不能说明一门编程语言好不好，或者一门语言所编写的代码数量多少。</p><p><img src="'+S+'" alt="202010011210999"></p><div class="tip custom-block"><p class="custom-block-title">笔者说</p><p>在笔者看来，数据还是能说明一些语言的好坏或流行度的。截止目前，即使谦虚一些，我们要学习的 Java（爪哇/国内音译加哇，扎哇），它仍然是最热门的编程语言之一。即便在网络上有一些人每天都在喊着不要学 Java，要学 Python，学 C，学 PHP，甚至还听过 PHP 是最好的语言，这种引战言论。</p><p>事实上呢？哪有什么完美的编程语言？只不过是不同的场景，谁更适合而已。<strong>而且处于当今时代的我们，只会一种编程语言已经无法适应快速迭代的互联网应用和企业需要了（全栈）。所以不学哪种编程语言本身就是个”伪命题”</strong> 。</p><p>尤其对于刚踏入编程领域的小伙伴们来讲，笔者个人认为，Java 是一门极其合适的入门和谋生语言！它在理解难度，语法规范，性能，流传广度、社区支持，企业需要和热度等方面都属于领先地位。稍后笔者就给你详细讲讲它的来历和能力。</p></div><h2 id="java-的前世今生" tabindex="-1">Java 的前世今生 <a class="header-anchor" href="#java-的前世今生" aria-label="Permalink to &quot;Java 的前世今生&quot;">​</a></h2><h3 id="java-的诞生" tabindex="-1">Java 的诞生 <a class="header-anchor" href="#java-的诞生" aria-label="Permalink to &quot;Java 的诞生&quot;">​</a></h3><p>Java 是 SUN Microsystems（国内译为升阳公司）于 1995 年推出的高级编程语言。下图是 Java 的共同创始人之一：詹姆斯·高斯林 James Gosling（被誉为 Java 之父）。2009 年，SUN 公司被 Oracle 并购，高斯林离职。截止目前，高斯林加入了亚马逊 AWS 工作。</p><p><img src="'+q+'" alt="202010011211888"></p><p>下图是 Java 的 Logo（一杯热气腾腾的咖啡，有传言 Java 也是由于大佬们爱喝印尼爪哇岛的咖啡而得名）。不过这两缕蒸汽是多么像大佬们头上稀疏的秀发。</p><p><img src="'+D+'" alt="202010011212999"></p><div class="tip custom-block"><p class="custom-block-title">《深入理解 Java 虚拟机》</p><p>1991 年 4 月，由 James Gosling 博士领导的绿色计划（Green Project）开始启动，此计划的目的是开发一种能够在各种消费性电子产品（如机顶盒、冰箱、收音机等）上运行的程序架构。这个计划的产品就是 Java 语言的前身：Oak（橡树）。Oak 当时在消费品市场上并不算成功，但随着 1995 年互联网潮流的兴起，Oak 迅速找到了最适合自己发展的市场定位并蜕变成为 Java 语言。[1]</p></div><h3 id="java-的发展" tabindex="-1">Java 的发展 <a class="header-anchor" href="#java-的发展" aria-label="Permalink to &quot;Java 的发展&quot;">​</a></h3><p>下图是 Java 的发展过程，重点关注一下 1995 年，1998 年，2009 年和 2013 年中期即可，了解下它的历史，才能让我们更好的与它&quot;对话和结伴&quot;。</p><p><img src="'+x+'" alt="202010011215888"></p><div class="tip custom-block"><p class="custom-block-title">《深入理解 Java 虚拟机》</p><p>1995 年 5 月 23 日，<strong>Oak 语言改名为 Java</strong> ，并且在 SunWorld 大会上正式发布 Java 1.0 版本。Java 语言第一次提出了“<strong>Write Once,Run Anywhere</strong> ”的口号。</p><p>1996 年 1 月 23 日，JDK 1.0 发布，Java 语言有了第一个正式版本的运行环境。JDK 1.0 提供了一个纯解释执行的 Java 虚拟机实现（Sun Classic VM）。JDK 1.0 版本的代表技术包括：Java 虚拟机、Applet、AWT 等。</p><p>1998 年 12 月 4 日，JDK 迎来了一个里程碑式的版本 JDK 1.2，工程代号为 Playground（竞技场），Sun 在这个版本中把 Java 技术体系拆分为 3 个方向，分别是面向桌面应用开发的<strong>J2SE</strong> （Java 2 Platform,Standard Edition）、面向企业级开发的<strong>J2EE</strong> （Java 2 Platform,Enterprise Edition）和面向手机等移动终端开发的<strong>J2ME</strong> （Java 2 Platform,Micro Edition）。在这个版本中出现的代表性技术非常多，如 EJB、Java Plug-in、Java IDL、Swing 等，并且这个版本中 Java 虚拟机第一次内置了 JIT（Just In Time）编译器（JDK 1.2 中曾并存过 3 个虚拟机，Classic VM、HotSpot VM 和 Exact VM，其中 Exact VM 只在 Solaris 平台出现过；后面两个虚拟机都是内置 JIT 编译器的，而之前版本所带的 Classic VM 只能以外挂的形式使用 JIT 编译器）。</p><p>1999 年 4 月 27 日，<strong>HotSpot</strong> 虚拟机发布，HotSpot 最初由一家名为“Longview Technologies”的小公司开发，因为 HotSpot 的优异表现，这家公司在 1997 年被 Sun 公司收购了。HotSpot 虚拟机发布时是作为 JDK 1.2 的附加程序提供的，<strong>后来它成为了 JDK 1.3 及之后所有版本的 Sun JDK 的默认虚拟机。</strong></p><p>2009 年 2 月 19 日，工程代号为 Dolphin（海豚）的 JDK 1.7 完成了其第一个里程碑版本。根据 JDK 1.7 的功能规划，一共设置了 10 个里程碑。最后一个里程碑版本原计划于 2010 年 9 月 9 日结束，但由于各种原因，JDK 1.7 最终无法按计划完成。在 JDK 1.7 开发期间，Sun 公司由于相继在技术竞争和商业竞争中都陷入泥潭，公司的股票市值跌至仅有高峰时期的 3%，已无力推动 JDK 1.7 的研发工作按正常计划进行。为了尽快结束 JDK 1.7 长期“跳票”的问题，<strong>Oracle 公司收购 Sun 公司</strong> 后不久便宣布将实行“B 计划”，大幅裁剪了 JDK 1.7 预定目标，以便保证 JDK 1.7 的正式版能够于 2011 年 7 月 28 日准时发布。[1]</p></div><div class="tip custom-block"><p class="custom-block-title">笔者说</p><p>2017 年 11 月，<strong>Oracle（甲骨文）将 Java EE（Java Enterprise Edition）移交给</strong> Eclipse 基金会，2018 年 3 月份 Eclipse 将其更名为 Jakarta EE。</p></div><h3 id="java-的能力" tabindex="-1">Java 的能力 <a class="header-anchor" href="#java-的能力" aria-label="Permalink to &quot;Java 的能力&quot;">​</a></h3><p>从 1998 年的 1.2 版本开始，Java 出现了 3 个方向版本，上面笔者也给你摘了一部分周老师的书籍内容。这三个版本分别是：<strong>面向桌面应用开发的 J2SE（Java 2 Platform,Standard Edition）、面向企业级开发的 J2EE（Java 2 Platform,Enterprise Edition）和面向手机等移动终端开发的 J2ME（Java 2 Platform,Micro Edition）</strong> 。</p><p>Java SE 是基础核心，Java ME 和 Java EE 是核心外的两个分支。无论是走 Java ME 还是 Java EE 都需要学习 Java SE，我们系列课程的前三小阶段就是在学习 Java SE 基础。另外以后我们主要从事的分支就是 Java EE，典型的产品就是天猫、京东等大型分布式应用。再进阶之后我们还可以进入热门的大数据领域，国内现在比较知名的大数据框架 Hadoop 就是 Java 语言编写的，而且现在国内做大数据的人才很多都是由原 Java 工程师进阶过去的。</p><p>还有非常重要的一点，<strong>Java 程序是跨平台的</strong> ，即 Java 程序可以运行在任何平台上，不需要做不同系统平台的兼容适配。 <strong>“write once , run anywhere.”</strong> ，稍后我们编写完第一个 Java 程序后会介绍一下这句口号及原理。</p><div class="tip custom-block"><p class="custom-block-title">笔者说</p><ol><li>因为 windows 的普及性，在桌面程序开发领域，微软的 C#语言更具有优势，开发游戏方面 C 和 C++性能和渲染上也更有优势，Java 几乎没有市场。</li><li>Java ME 已经凉凉，被 Android 等抢占了市场，不知道你有没有用过诺基亚等老式手机？还记得 Java 2D 游戏吗？</li><li>Android（Andorid 不是编程语言）虽然在 2017 年 Google 将 Kotlin 正式列为官方支持开发语言，但 Java 目前仍是其主要开发语言，原因是 Android 的底层有大量的 Java API(可延伸阅读 Oracle 与 Google 的官司大战)。</li></ol></div><p><img src="'+A+'" alt="202010011216999"></p><div class="tip custom-block"><p class="custom-block-title">《深入理解 Java 虚拟机》</p><p>Java 不仅仅是一门编程语言，还是一个由一系列计算机软件和规范形成的技术体系，这个技术体系提供了完整的用于软件开发和跨平台部署的支持环境，并<strong>广泛应用于嵌入式系统、移动终端、企业服务器、大型机等各种场合</strong> 。时至今日，Java 技术体系已经吸引了 900 多万软件开发者，这是全球最大的软件开发团队。使用 Java 的设备多达几十亿台，其中包括 11 亿多台个人计算机、30 亿部移动电话及其他手持设备、数量众多的智能卡，以及大量机顶盒、导航系统和其他设备。[1]</p></div><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to &quot;参考文献&quot;">​</a></h2><p>[1]周志明. 深入理解 Java 虚拟机[M]. 第 3 版. 北京:机械工业出版社,2019</p>',52);function O(a,j,C,M,V,I){const e=i,n=l("ClientOnly");return s(),c("div",null,[T,v(n,null,{default:J(()=>{var t,o;return[(((t=a.$frontmatter)==null?void 0:t.aside)??!0)&&(((o=a.$frontmatter)==null?void 0:o.showArticleMetadata)??!0)?(s(),m(e,{key:0,article:a.$frontmatter},null,8,["article"])):h("",!0)]}),_:1}),w])}const $=p(K,[["render",O]]);export{y as __pageData,$ as default};
